from typing import List, Optional

class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

def build_list(nums: List[int]) -> Optional[ListNode]:
    dummy = ListNode(0)
    cur = dummy
    for n in nums:
        cur.next = ListNode(n)
        cur = cur.next
    return dummy.next

def list_to_arr(head: Optional[ListNode]) -> List[int]:
    result = []
    while head:
        result.append(head.val)
        head = head.next
    return result

def reverse_list(head: List[int]) -> List[int]:
    head = build_list(head)

    def reverse(node):
        if not node or not node.next:
            return node
        new_head = reverse(node.next)
        node.next.next = node
        node.next = None
        return new_head

    return list_to_arr(reverse(head))

class ListNode {
  constructor(val = 0, next = null) { this.val = val; this.next = next; }
}
function buildList(nums) {
  const dummy = new ListNode(0); let cur = dummy;
  for (const n of nums) { cur.next = new ListNode(n); cur = cur.next; }
  return dummy.next;
}
function listToArr(head) {
  const res = []; while (head) { res.push(head.val); head = head.next; } return res;
}
function reverseList(head) {
    head = buildList(head);
    let prev = null, curr = head;
    while (curr) {
        const next = curr.next;
        curr.next = prev;
        prev = curr;
        curr = next;
    }
    return listToArr(prev);
}
